/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently supports email as the only notification channel.
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - immediate: sent as soon as the event occurs
 * - daily_digest: batched and sent once per day
 * - weekly_digest: batched and sent once per week
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Persisted user notification preferences.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  emailEnabled: boolean;
  emailFrequency: EmailFrequency;
  enabledCategories: NotificationType[];
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  enabledCategories?: NotificationType[];
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  enabledCategories?: NotificationType[];
}

/**
 * All available notification categories.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default preferences for new users — all emails enabled, immediate delivery.
 */
export const DEFAULT_PREFERENCES: Omit<UserPreferences, 'id' | 'userId' | 'createdAt' | 'updatedAt'> = {
  emailEnabled: true,
  emailFrequency: 'immediate',
  enabledCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class UserPreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      emailEnabled: record['emailEnabled'] as boolean,
      emailFrequency: record['emailFrequency'] as EmailFrequency,
      enabledCategories: JSON.parse(record['enabledCategories'] as string) as NotificationType[],
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.emailEnabled,
      emailFrequency: entity.emailFrequency,
      enabledCategories: JSON.stringify(entity.enabledCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * User notification preferences service.
 *
 * Manages user notification preferences — what notifications they receive
 * and how they are delivered.
 *
 * Depends on:
 * - UserPreferencesRepository for data access
 * - EventBus for reacting to user creation (auto-create default preferences)
 */

import type { EventBus } from '../events/event-bus.js';
import type { UserCreatedEvent } from '../events/event-types.js';
import type { UserPreferencesRepository } from '../repositories/user-preferences.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import {
  DEFAULT_PREFERENCES,
  ALL_NOTIFICATION_CATEGORIES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private repository: UserPreferencesRepository,
    private eventBus: EventBus,
  ) {
    this.registerEventHandlers();
  }

  /**
   * Subscribe to user creation events to auto-create default preferences.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      this.createDefaultPreferences(event.user.id);
    });
  }

  /**
   * Create default preferences for a new user.
   */
  private createDefaultPreferences(userId: string): void {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      this.logger.info(`Preferences already exist for user ${userId}`);
      return;
    }

    this.logger.info(`Creating default preferences for user ${userId}`);
    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      ...DEFAULT_PREFERENCES,
      enabledCategories: [...DEFAULT_PREFERENCES.enabledCategories],
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(preferences);
  }

  /**
   * Get preferences for a user. Returns undefined if not found.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Create preferences for a user with custom settings.
   * Throws if the user already has preferences.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user ${input.userId}`);
    }

    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      emailEnabled: input.emailEnabled ?? DEFAULT_PREFERENCES.emailEnabled,
      emailFrequency: input.emailFrequency ?? DEFAULT_PREFERENCES.emailFrequency,
      enabledCategories: input.enabledCategories
        ? [...input.enabledCategories]
        : [...DEFAULT_PREFERENCES.enabledCategories],
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(preferences);
    this.logger.info(`Created preferences for user ${input.userId}`);
    return preferences;
  }

  /**
   * Update preferences for a user.
   * Throws if the user has no preferences.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user ${userId}`);
    }

    const updates: Partial<UserPreferences> = { updatedAt: new Date() };

    if (input.emailEnabled !== undefined) {
      updates.emailEnabled = input.emailEnabled;
    }
    if (input.emailFrequency !== undefined) {
      updates.emailFrequency = input.emailFrequency;
    }
    if (input.enabledCategories !== undefined) {
      updates.enabledCategories = [...input.enabledCategories];
    }

    const updated = this.repository.update(existing.id, updates);
    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user based on their preferences.
   * Returns true if the notification should be sent.
   *
   * If no preferences exist for the user, defaults to allowing the notification
   * (opt-out model: notifications are sent unless explicitly disabled).
   */
  shouldSendNotification(userId: string, notificationType: NotificationType): boolean {
    const preferences = this.repository.findByUserId(userId);

    if (!preferences) {
      return true;
    }

    if (!preferences.emailEnabled) {
      return false;
    }

    return preferences.enabledCategories.includes(notificationType);
  }

  /**
   * Get the email frequency setting for a user.
   * Returns 'immediate' if no preferences exist.
   */
  getEmailFrequency(userId: string): UserPreferences['emailFrequency'] {
    const preferences = this.repository.findByUserId(userId);
    return preferences?.emailFrequency ?? 'immediate';
  }
}

