import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { UserPreferencesRepository } from '../../src/repositories/user-preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import type { UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let eventBus: EventBus;
  let repository: UserPreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    repository = new UserPreferencesRepository(db);
    service = new PreferencesService(repository, eventBus);
    resetPreferencesIdCounter();
  });

  describe('auto-create on user:created', () => {
    it('should create default preferences when a user is created', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
      expect(prefs!.emailEnabled).toBe(true);
      expect(prefs!.emailFrequency).toBe('immediate');
      expect(prefs!.enabledCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ]);
    });

    it('should not overwrite existing preferences on duplicate user:created event', async () => {
      service.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
      });

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const prefs = service.getPreferences('user-1');
      expect(prefs!.emailEnabled).toBe(false);
    });
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults when no options provided', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('immediate');
      expect(prefs.enabledCategories).toHaveLength(4);
    });

    it('should create preferences with custom settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        emailEnabled: true,
        emailFrequency: 'daily_digest',
        enabledCategories: ['order_confirmation'],
      });

      expect(prefs.emailFrequency).toBe('daily_digest');
      expect(prefs.enabledCategories).toEqual(['order_confirmation']);
    });

    it('should throw when preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createPreferences({ userId: 'user-1' });
      const p2 = service.createPreferences({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled setting', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', { emailEnabled: false });

      expect(updated.emailEnabled).toBe(false);
      expect(updated.emailFrequency).toBe('immediate');
    });

    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        emailFrequency: 'weekly_digest',
      });

      expect(updated.emailFrequency).toBe('weekly_digest');
    });

    it('should update enabled categories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        enabledCategories: ['order_confirmation', 'welcome'],
      });

      expect(updated.enabledCategories).toEqual(['order_confirmation', 'welcome']);
    });

    it('should throw when no preferences exist', () => {
      expect(() =>
        service.updatePreferences('user-1', { emailEnabled: false }),
      ).toThrow('No preferences found for user user-1');
    });

    it('should update the updatedAt timestamp', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });
      const originalUpdatedAt = prefs.updatedAt;

      const updated = service.updatePreferences('user-1', { emailEnabled: false });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(originalUpdatedAt.getTime());
    });
  });

  describe('shouldSendNotification', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not in enabled list', () => {
      service.createPreferences({
        userId: 'user-1',
        enabledCategories: ['welcome'],
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return true for subscribed category even when others are disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        enabledCategories: ['order_confirmation'],
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'order_status_update')).toBe(false);
    });
  });

  describe('getEmailFrequency', () => {
    it('should return immediate when no preferences exist', () => {
      expect(service.getEmailFrequency('user-1')).toBe('immediate');
    });

    it('should return the configured frequency', () => {
      service.createPreferences({
        userId: 'user-1',
        emailFrequency: 'daily_digest',
      });

      expect(service.getEmailFrequency('user-1')).toBe('daily_digest');
    });
  });

  describe('getPreferences', () => {
    it('should return undefined for unknown user', () => {
      expect(service.getPreferences('user-999')).toBeUndefined();
    });

    it('should return preferences for known user', () => {
      service.createPreferences({ userId: 'user-1' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });
});
